input.command:
kubectl patch statefulset es-cluster -n elasticsearch --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "es-plugins",
      "emptyDir": {}
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "es-keystore",
      "emptyDir": {}
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "es-secure-settings",
      "secret": {
        "secretName": "es-secure-settings"
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/initContainers",
    "value": [
      {
        "name": "setup-plugins-keystore",
        "image": "docker.elastic.co/elasticsearch/elasticsearch:7.17.9",
        "command": ["/bin/bash", "-c"],
        "args": [
          "set -e\n\n# Install repository-s3 plugin into shared plugins volume\nelasticsearch-plugin install --batch repository-s3\ncp -r /usr/share/elasticsearch/plugins/repository-s3 /plugins/\n\n# Create keystore and add S3 credentials from mounted secret\nelasticsearch-keystore create -s 2>/dev/null || true\ncat /secure-settings/s3.client.default.access_key | elasticsearch-keystore add --stdin s3.client.default.access_key -f\ncat /secure-settings/s3.client.default.secret_key | elasticsearch-keystore add --stdin s3.client.default.secret_key -f\n\n# Copy keystore to shared volume\ncp /usr/share/elasticsearch/config/elasticsearch.keystore /keystore/\necho \"Init complete: plugin + keystore ready\"\n"
        ],
        "volumeMounts": [
          {
            "name": "es-plugins",
            "mountPath": "/plugins"
          },
          {
            "name": "es-keystore",
            "mountPath": "/keystore"
          },
          {
            "name": "es-secure-settings",
            "mountPath": "/secure-settings"
          }
        ]
      }
    ]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "es-plugins",
      "mountPath": "/usr/share/elasticsearch/plugins/repository-s3"
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "es-keystore",
      "mountPath": "/usr/share/elasticsearch/config/elasticsearch.keystore",
      "subPath": "elasticsearch.keystore"
    }
  }
]' 2>&1

